module shift_register (
	input clk,
	input reset,
	input load,
	input [15:0] data_in,
	output reg [15:0] data_out
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset)
		data_out <= 16'b0000000000000000;
	else if (load)
		data_out <= data_in;
	else
		data_out <= data_out << 1;
end

endmodule
